const AWS = require('aws-sdk');

exports.handler = async (event) => {
  // Get the object from the event and show its content type
  const bucket = event.Records[0].s3.bucket.name;
  const key = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));
  console.log(`Processing object ${key} from bucket ${bucket}`);
  const s3 = new AWS.S3({ region: 'us-east-1' });
  const object = await s3.getObject({ Bucket: bucket, Key: key }).promise();
  console.log(`File content type: ${object.ContentType}`);
  
  // Process the file and save results to another S3 location
  const processedData = processFile(object.Body);
  const outputKey = `${key.split('.')[0]}_processed.txt`;
  await s3.putObject({ Bucket: bucket, Key: outputKey, Body: processedData }).promise();
  
  // Log the results
  console.log(`File ${key} processed and saved to S3 with key ${outputKey}`);
};

